import sys

def find_kth(a, b, k):
    m, n = len(a), len(b)
    if m > n:
        return find_kth(b, a, k)
    low = max(0, k - n)
    high = min(k, m)
    while low <= high:
        cut1 = (low + high) // 2
        cut2 = k - cut1
        l1 = -10**18 if cut1 == 0 else a[cut1 - 1]
        l2 = -10**18 if cut2 == 0 else b[cut2 - 1]
        r1 = 10**18 if cut1 == m else a[cut1]
        r2 = 10**18 if cut2 == n else b[cut2]
        if l1 <= r2 and l2 <= r1:
            return max(l1, l2)
        elif l1 > r2:
            high = cut1 - 1
        else:
            low = cut1 + 1
    return -1

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        M = int(next(it)); N = int(next(it))
        A = [int(next(it)) for _ in range(M)]
        B = [int(next(it)) for _ in range(N)]
        K = int(next(it))
        out.append(str(find_kth(A, B, K)))
    sys.stdout.write('\n'.join(out))

